// Welcome to Outline!
// Every binding's type is inferred — you never write a single annotation.

let name    = "Outline";   // → String
let version = 1;           // → Int
let pi      = 3.14159;     // → Double
let flag    = true;        // → Bool

// String concatenation produces a String
let greeting = "Hello, " + name + " v" + to_str(version) + "!";

greeting;

// Type conversion
let s = to_str(42);         // "42"    String
