let f = to_float("3.14");   // 3.14    Double

// Introspection
let t1 = type_of("hello");  // "String"
let t2 = type_of(99);       // "Int"
let t3 = type_of(true);     // "Bool"

// String length
let l = len("Outline");     // 7

// Assertion — throws if false
assert(n == 123);
assert(l == 7);

// Print to Console panel
print("types: " + t1 + ", " + t2);

