// Single-argument lambdas
let double  = x -> x * 2;
let negate  = x -> -x;
let greet   = name -> "Hello, " + name + "!";
let is_even = x -> x % 2 == 0;

// Multi-line function body with a block
let abs = x -> {
    let pos = if (x < 0) -x else x;
    pos
};

let r1 = double(7);        // 14
let r2 = greet("Alice");   // "Hello, Alice!"
let r3 = is_even(6);       // true
let r4 = abs(-15);         // 15

r1;

// All functions are curried: f(a)(b) not f(a, b)
let add  = x -> y -> x + y;         // Int → Int → Int
let mul  = x -> y -> x * y;
let clamp = lo -> hi -> v -> if (v < lo) lo else if (v > hi) hi else v;

// Partial application — fix one argument, get a new function
let add5   = add(5);           // Int → Int
let double = mul(2);           // Int → Int
let norm   = clamp(0)(100);    // Int → Int  (clamp to [0,100])

// Use the specialised functions
let r1 = add5(3);              // 8
let r2 = double(21);           // 42
let r3 = norm(150);            // 100
let r4 = norm(-5);             // 0

r2;

// Classic HOF combinators
let apply   = f -> x -> f(x);
let twice   = f -> x -> f(f(x));
let compose = f -> g -> x -> f(g(x));
let flip    = f -> x -> y -> f(y)(x);

let inc    = x -> x + 1;
let double = x -> x * 2;
let square = x -> x * x;
let sub    = x -> y -> x - y;

// compose: (double ∘ inc)(5) = double(6) = 12
let double_after_inc = compose(double)(inc);

// twice(double)(3) = double(double(3)) = 12
let r1 = twice(double)(3);           // 12
let r2 = double_after_inc(5);        // 12
let r3 = compose(square)(double)(3); // square(6) = 36
let r4 = flip(sub)(3)(10);           // 10 - 3 = 7

r3;

// Factorial: Int → Int (inferred)
let fact = n -> if (n <= 1) 1 else n * fact(n - 1);

// Fibonacci
let fib  = n -> if (n <= 1) n else fib(n - 1) + fib(n - 2);

// GCD via Euclidean algorithm (curried binary)
let gcd  = x -> y -> if (y == 0) x else gcd(y)(x % y);

// Gauss sum: 1+2+...+n
let sum_to = n -> if (n <= 0) 0 else n + sum_to(n - 1);

let f6  = fact(6);          // 720
let f10 = fib(10);          // 55
let g   = gcd(48)(18);      // 6
let s   = sum_to(100);      // 5050

console.log("fact(6) = " + to_str(f6));
console.log("fib(10) = " + to_str(f10));
console.log("sum(100) = " + to_str(s));

s;

