// `this{field=value}` is a copy constructor — creates a modified copy.
// The result has the same type as the receiver, so method chains stay intact.

outline Vec2 = {
    x: Int,
    y: Int,
    move_x: (dx: Int) -> this{x = x + dx},
    move_y: (dy: Int) -> this{y = y + dy},
    scale:  (f: Int)  -> this{x = x * f, y = y * f}
};

let origin = Vec2 { x = 0, y = 0 };

// Chained copy-construction — each call returns Vec2
let p = origin.move_x(3).move_y(4).scale(2);

console.log("x = " + to_str(p.x) + ", y = " + to_str(p.y));

// The original is unchanged (immutable update)
console.log("origin x = " + to_str(origin.x));   // still 0

p.x;

// `with expr as name { body }` scopes a resource to the block.
// If the result has open/close methods, they are called automatically.
// The value of the `with` expression is the value of `body`.

let get_file = name -> {
    open  = () -> print("opening..."  + name),
    close = () -> print("closing..."  + name),
    do    = () -> print("processing: " + name)
};

// Open is called on entry, close on exit — body result is the expression value
let result = with get_file("report.csv") as file {
    file.do();
    "done"   // last expression is the value of the with block
};

console.log("result = " + result);

result;

