// Simple sum types — each variant is a constant
outline Direction = North | South | East | West;
outline Season    = Spring | Summer | Autumn | Winter;
outline Weekday   = Mon | Tue | Wed | Thu | Fri | Sat | Sun;

let dir  = North;
let day  = Fri;

// Pattern match over the variants
