// Variant types with data — each branch is a small entity
outline Shape = Circle { r: Int }
              | Rect   { w: Int, h: Int }
              | Triangle { base: Int, height: Int }
              | Dot;

// Pattern match unpacks fields inline
let area = s -> match s {
    Circle   { r }              -> r * r,
    Rect     { w, h }           -> w * h,
    Triangle { base, height }   -> (base * height) / 2,
    Dot                         -> 0
};

let describe = s -> match s {
    Circle { r } if r > 10 -> "large circle (r=" + to_str(r) + ")",
    Circle { r }           -> "small circle (r=" + to_str(r) + ")",
    Rect   { w, h }        -> to_str(w) + "x" + to_str(h) + " rect",
    _                      -> "other shape"
};

let shapes = [Circle{r=5}, Rect{w=4, h=6}, Circle{r=15}, Dot];
let areas  = shapes.map(s -> area(s));

console.log("areas: " + to_str(areas));

area(Rect{w=4, h=6});

