// .some(pred)  → true if ANY element satisfies pred  (stops at first match)
// .every(pred) → true if ALL elements satisfy pred   (stops at first miss)

let nums = [1, 3, 5, 7, 8, 11, 13];

let has_even = nums.some(x -> x % 2 == 0);    // true  (stops at 8)
let all_odd  = nums.every(x -> x % 2 != 0);   // false (stops at 8)

// Works on entity arrays too
let players = [
    {name = "Alice", score = 85},
    {name = "Bob",   score = 95},
    {name = "Carol", score = 72}
];

let has_ace  = players.some(p -> p.score > 90);    // true  (stops at Bob)
let all_pass = players.every(p -> p.score >= 70);  // true

console.log("has_even: " + to_str(has_even));
console.log("has_ace : " + to_str(has_ace));
console.log("all_pass: " + to_str(all_pass));

(has_even, all_odd, has_ace, all_pass)

// .take_while(pred) → longest prefix where all elements satisfy pred
// .drop_while(pred) → suffix after dropping the matching prefix

let nums = [2, 4, 6, 7, 9, 10, 12];

// Even-prefix and the rest
let evens = nums.take_while(x -> x % 2 == 0);   // [2, 4, 6]
let rest  = nums.drop_while(x -> x % 2 == 0);   // [7, 9, 10, 12]

// Partition a sorted list at threshold
let sorted = [1, 3, 5, 8, 12, 15, 20];
let small  = sorted.take_while(x -> x < 10);    // [1, 3, 5, 8]
let large  = sorted.drop_while(x -> x < 10);    // [12, 15, 20]

let small_sum = small.reduce(acc -> x -> acc + x)(0);   // 17

console.log("evens : " + to_str(evens));
console.log("small : " + to_str(small));
console.log("large : " + to_str(large));

(evens, rest, small_sum)

// ── What TypeScript needs:
//    (p: { given: string; surname: string }) => ...  ← explicit annotation
//
// ── What Haskell needs:
//    data Person = Person { given :: String, surname :: String }  ← named type
//
// ── What Outline needs: NOTHING.
// The structural type of `p` is synthesised from how the function accesses fields.

let full_name = p -> (p.given + " ") + p.surname;
let greeting  = p -> "Hello, " + full_name(p) + "!";
let initials  = p -> to_str(p.given) + "." + to_str(p.surname);

// GCP infers: p : { given: String, surname: String }
// Extra fields (age, title) are allowed — structural subtyping.

