k1.issuer;

// Church numerals: numbers encoded purely as higher-order functions.
// zero = f -> x -> x
// succ = n -> f -> x -> f(n(f)(x))
//
// GCP infers the complete type of every step — zero annotations.

let zero  = f -> x -> x;
let succ  = n -> f -> x -> f(n(f)(x));

let one   = succ(zero);
let two   = succ(one);
let three = succ(two);
let four  = succ(three);
let five  = succ(four);

// Decode: apply to (x -> x+1) starting from 0
let decode = n -> n(x -> x + 1)(0);

// Church addition: m + n = m(succ)(n)
let church_add = m -> n -> f -> x -> m(f)(n(f)(x));
let church_mul = m -> n -> f -> m(n(f));

let eight = church_add(three)(five);
let ten   = church_mul(two)(five);

console.log("3 + 5 = " + to_str(decode(eight)));
console.log("2 * 5 = " + to_str(decode(ten)));

decode(ten);

