// append(path)(content) → Unit
IO.append("/data/hello.txt")("\nLine 2 appended.");

// read(path) → String
let content = IO.read("/data/hello.txt");
console.log("content: " + content);

// exists(path) → Bool
let ok  = IO.exists("/data/notes.txt");   // true
let nok = IO.exists("/data/missing.txt"); // false
console.log("notes exists: " + to_str(ok));

// list(prefix) → [String]  (all paths starting with prefix)
let files = IO.list("/data/");
console.log("files: " + to_str(files));

// delete(path) → Unit
IO.delete("/data/notes.txt");
let after = IO.list("/data/");
console.log("after delete: " + to_str(after));

content;
